import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { FaUser, FaUserMd, FaHospital, FaEye, FaEyeSlash, FaSpinner } from 'react-icons/fa';

const Login = ({ onLogin }) => {
  const { t, i18n } = useTranslation();
  const [selectedRole, setSelectedRole] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [step, setStep] = useState('role'); // role, credentials
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [language, setLanguage] = useState('en');
  const [error, setError] = useState('');

  const roles = [
    {
      id: 'patient',
      name: t('patient'),
      icon: FaUser,
      color: 'bg-blue-500',
      description: t('patient_desc'),
      usernamePrefix: 'p',
      sampleUsername: 'p001'
    },
    {
      id: 'doctor',
      name: t('doctor'),
      icon: FaUserMd,
      color: 'bg-green-500',
      description: t('doctor_desc'),
      usernamePrefix: 'd',
      sampleUsername: 'd001'
    },
    {
      id: 'pharmacist',
      name: t('pharmacist'),
      icon: FaHospital,
      color: 'bg-purple-500',
      description: t('pharmacist_desc'),
      usernamePrefix: 'pm',
      sampleUsername: 'pm001'
    }
  ];

  const languages = [
    { code: 'en', name: 'English' },
    { code: 'hi', name: 'हिंदी' },
    { code: 'pa', name: 'ਪੰਜਾਬੀ' }
  ];

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setStep('credentials');
    setError('');
    setUsername('');
    setPassword('');
  };

  const handleLogin = async () => {
    if (!username || !password) {
      setError('Please enter both username and password');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          username: username,
          password: password
        })
      });
      
      const data = await response.json();
      
      if (response.ok) {
        // Store token in localStorage
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        
        // Call onLogin with user data
        onLogin({
          ...data.user,
          token: data.token
        });
      } else {
        setError(data.message || 'Login failed');
      }
    } catch (err) {
      console.error('Login error:', err);
      setError('Network error. Please check your connection.');
    } finally {
      setIsLoading(false);
    }
  };

  const changeLanguage = (langCode) => {
    setLanguage(langCode);
    i18n.changeLanguage(langCode);
  };

  const getCurrentRole = () => {
    return roles.find(role => role.id === selectedRole);
  };

  const handleBack = () => {
    setStep('role');
    setSelectedRole('');
    setError('');
    setUsername('');
    setPassword('');
  };

  const getPasswordForRole = (role) => {
    switch(role) {
      case 'patient': return 'patient123';
      case 'doctor': return 'doctor123';
      case 'pharmacist': return 'pharmacy123';
      default: return '';
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        {/* Language Selector */}
        <div className="mb-6 flex justify-center">
          <div className="bg-white rounded-full p-1 shadow-lg">
            {languages.map((lang) => (
              <button
                key={lang.code}
                onClick={() => changeLanguage(lang.code)}
                className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
                  language === lang.code
                    ? 'bg-blue-500 text-white shadow-md'
                    : 'text-gray-600 hover:bg-blue-50'
                }`}
              >
                {lang.name}
              </button>
            ))}
          </div>
        </div>

        {/* Logo and Title */}
        <div className="text-center mb-8">
          <div className="w-20 h-20 bg-blue-500 rounded-full mx-auto mb-4 flex items-center justify-center">
            <span className="text-3xl font-bold text-white">H</span>
          </div>
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Helio</h1>
          <p className="text-gray-600">{t('welcome_subtitle')}</p>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-6">
          {/* Step 1: Role Selection */}
          {step === 'role' && (
            <div>
              <h2 className="text-xl font-bold text-center mb-6">{t('select_role')}</h2>
              <div className="space-y-4">
                {roles.map((role) => {
                  const IconComponent = role.icon;
                  return (
                    <button
                      key={role.id}
                      onClick={() => handleRoleSelect(role.id)}
                      className="w-full p-4 border-2 border-gray-200 rounded-xl hover:border-blue-300 hover:bg-blue-50 transition-all group"
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 ${role.color} rounded-full flex items-center justify-center`}>
                          <IconComponent className="text-white text-xl" />
                        </div>
                        <div className="text-left flex-1">
                          <h3 className="font-semibold text-gray-900">{role.name}</h3>
                          <p className="text-sm text-gray-600">{role.description}</p>
                          <p className="text-xs text-blue-600 mt-1">Sample: {role.sampleUsername}</p>
                        </div>
                      </div>
                    </button>
                  );
                })}
              </div>
              
              {/* Demo Credentials Info */}
              <div className="mt-6 p-4 bg-blue-50 rounded-lg">
                <h4 className="font-semibold text-blue-900 mb-2">Demo Credentials:</h4>
                <div className="text-sm text-blue-700 space-y-1">
                  <p><strong>Patients:</strong> p001, p002, p003 (password: patient123)</p>
                  <p><strong>Doctors:</strong> d001, d002, d003 (password: doctor123)</p>
                  <p><strong>Pharmacists:</strong> pm001, pm002, pm003 (password: pharmacy123)</p>
                </div>
              </div>
            </div>
          )}

          {/* Step 2: Login Credentials */}
          {step === 'credentials' && (
            <div>
              <div className="text-center mb-6">
                <div className={`w-16 h-16 ${getCurrentRole()?.color} rounded-full mx-auto mb-3 flex items-center justify-center`}>
                  {React.createElement(getCurrentRole()?.icon, { className: "text-white text-2xl" })}
                </div>
                <h2 className="text-xl font-bold">{getCurrentRole()?.name} Login</h2>
                <p className="text-gray-600 text-sm mt-1">Enter your credentials to continue</p>
              </div>

              {error && (
                <div className="mb-4 p-3 bg-red-100 border border-red-300 rounded-lg text-red-700 text-sm">
                  {error}
                </div>
              )}

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Username
                  </label>
                  <input
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    placeholder={`e.g., ${getCurrentRole()?.sampleUsername}`}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    disabled={isLoading}
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Password
                  </label>
                  <div className="relative">
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder={`Demo password: ${getPasswordForRole(selectedRole)}`}
                      className="w-full px-4 py-3 pr-12 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      disabled={isLoading}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500 hover:text-gray-700"
                    >
                      {showPassword ? <FaEyeSlash /> : <FaEye />}
                    </button>
                  </div>
                </div>

                <div className="flex gap-3 pt-2">
                  <button
                    onClick={handleBack}
                    className="flex-1 py-3 px-4 border border-gray-300 rounded-lg text-gray-700 font-medium hover:bg-gray-50 transition-colors"
                    disabled={isLoading}
                  >
                    Back
                  </button>
                  <button
                    onClick={handleLogin}
                    disabled={isLoading || !username || !password}
                    className="flex-1 py-3 px-4 bg-blue-500 text-white rounded-lg font-medium hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center justify-center gap-2"
                  >
                    {isLoading ? (
                      <>
                        <FaSpinner className="animate-spin" />
                        Logging in...
                      </>
                    ) : (
                      'Login'
                    )}
                  </button>
                </div>
              </div>

              {/* Quick Fill Buttons */}
              <div className="mt-4 p-3 bg-gray-50 rounded-lg">
                <p className="text-xs text-gray-600 mb-2">Quick fill for demo:</p>
                <button
                  onClick={() => {
                    setUsername(getCurrentRole()?.sampleUsername);
                    setPassword(getPasswordForRole(selectedRole));
                  }}
                  className="text-xs text-blue-600 hover:text-blue-800 underline"
                >
                  Fill sample credentials
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="text-center mt-6 text-sm text-gray-500">
          <p>{t('healthcare_access')} • Nabha, Punjab</p>
        </div>
      </div>
    </div>
  );
};

export default Login;
